1	/*
2	Kernels for layernorm forward pass.
3	
4	Compile example:
5	nvcc -O3 --use_fast_math -lcublas -lcublasLt layernorm_forward.cu -o layernorm_forward
6	
7	version 1 is naive port from CPU code to kernel: parallelizes over B,T, loops over C
8	./layernorm_forward 1
9	
10	version 2 parallelizes over all of B,T,C
11	./layernorm_forward 2
12	
13	version 3 uses cooperative groups to parallelize over all of B,T,C
14	./layernorm_forward 3
15	
16	version 4 uses a more clever way to estimate variance, var(x) = mean(x**2) - mean(x)**2
17	          (allowing us to do a single pass over x on load)
18	./layernorm_forward 4
19	
20	verstion 5 allocates blocks per row instead of warps per row, same alg as 4 otherwise
21	./layernorm_forward 5
22	*/
23	
24	#include <stdio.h>
25	#include <stdlib.h>
26	#include <cuda_runtime.h>
27	#include <assert.h>
28	#include <cooperative_groups.h>
29	#include <cooperative_groups/reduce.h>
30	#include "common.h"
31	// ----------------------------------------------------------------------------
32	// CPU code reference
33	
34	// GPT-2 layernorm forward pass
35	void layernorm_forward_cpu(float* out, float* mean, float* rstd,
36	                       const float* inp, const float* weight, const float* bias,
37	                       int B, int T, int C) {
38	    float eps = 1e-5f;
39	    for (int b = 0; b < B; b++) {
40	        for (int t = 0; t < T; t++) {
41	            // seek to the input position inp[b,t,:]
42	            const float* x = inp + b * T * C + t * C;
43	            // calculate the mean
44	            float m = 0.0f;
45	            for (int i = 0; i < C; i++) {
46	                m += x[i];
47	            }
48	            m = m/C;
49	            // calculate the variance (without any bias correction)
50	            float v = 0.0f;
51	            for (int i = 0; i < C; i++) {
52	                float xshift = x[i] - m;
53	                v += xshift * xshift;
54	            }
55	            v = v/C;
56	            // calculate the rstd
57	            float s = 1.0f / sqrtf(v + eps);
58	            // seek to the output position in out[b,t,:]
59	            float* out_bt = out + b * T * C + t * C;
60	            for (int i = 0; i < C; i++) {
61	                float n = (s * (x[i] - m)); // normalized output
62	                float o = n * weight[i] + bias[i]; // scale and shift it
63	                out_bt[i] = o; // write
64	            }
65	            // cache the mean and rstd for the backward pass later
66	            mean[b * T + t] = m;
67	            rstd[b * T + t] = s;
68	        }
69	    }
70	}
71	
72	// ----------------------------------------------------------------------------
73	// GPU kernels
74	
75	// naive drag and drop implementation into kernel, parallelize over B,T, loop over C
76	__global__ void layernorm_forward_kernel1(float* out, float* mean, float* rstd,
77	                                 const float* inp, const float* weight, const float* bias,
78	                                 int N, int C) {
79	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
80	    float eps = 1e-5f;
81	
82	    if (idx < N) {
83	        // seek to the input position inp[idx,:]
84	        const float* x = inp + idx * C;
85	        // calculate the mean
86	        float m = 0.0f;
87	        for (int i = 0; i < C; i++) {
88	            m += x[i];
89	        }
90	        m = m / C;
91	        // calculate the variance (without any bias correction)
92	        float v = 0.0f;
93	        for (int i = 0; i < C; i++) {
94	            float xshift = x[i] - m;
95	            v += xshift * xshift;
96	        }
97	        v = v / C;
98	        // calculate the rstd
99	        float s = 1.0f / sqrtf(v + eps);
100	        // seek to the output position in out[idx,:]
101	        float* out_idx = out + idx * C;
102	        for (int i = 0; i < C; i++) {
103	            float n = (s * (x[i] - m)); // normalized output
104	            float o = n * weight[i] + bias[i]; // scale and shift it
105	            out_idx[i] = o; // write
106	        }
107	        // cache the mean and rstd for the backward pass later
108	        mean[idx] = m;
109	        rstd[idx] = s;
110	    }
111	}
112	
113	__global__ void mean_kernel(float* mean, const float* inp, int N, int C, int block_size) {
114	    extern __shared__ float shared[];
115	    int idx = blockIdx.x; // range [0, B*T)
116	    int tid = threadIdx.x; // range [0, block_size)
117	    const float* x = inp + idx * C;
118	    // thread coarsening
119	    float sum = 0.0f;
120	    for (int i = tid; i < C; i += block_size) {
121	        sum += x[i];
122	    }
123	    shared[tid] = sum;
124	    __syncthreads();
125	    // reductions
126	    for (int stride = block_size / 2; stride >= 1; stride /= 2) {
127	        __syncthreads();
128	        if (tid < stride) {
129	            shared[tid] += shared[tid + stride];
130	        }
131	    }
132	    // write the final result (at thread 0) to global memory
133	    if (tid == 0) {
134	        mean[idx] = shared[0] / C;
135	    }
136	}
137	
138	__global__ void rstd_kernel(float* rstd, const float* inp, const float* mean, int N, int C, int block_size) {
139	    extern __shared__ float shared[];
140	    int idx = blockIdx.x; // range [0, B*T)
141	    int tid = threadIdx.x; // range [0, block_size)
142	    const float* x = inp + idx * C;
143	    float m = mean[idx];
144	    // thread coarsening
145	    float sum = 0.0f;
146	    for (int i = tid; i < C; i += block_size) {
147	        float diff = x[i] - m;
148	        sum += diff * diff;
149	    }
150	    shared[tid] = sum;
151	    __syncthreads();
152	    // reductions
153	    for (int stride = block_size / 2; stride >= 1; stride /= 2) {
154	        __syncthreads();
155	        if (tid < stride) {
156	            shared[tid] += shared[tid + stride];
157	        }
158	    }
159	    // write the final result (at thread 0) to global memory
160	    if (tid == 0) {
161	        rstd[idx] = 1.0f / sqrtf(shared[0] / C + 1e-5f);
162	    }
163	}
164	
165	__global__ void normalization_kernel(float* out, const float* inp, float* mean, float* rstd,
166	                                     const float* weight, const float* bias, int B, int T, int C) {
167	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
168	
169	    int bt = idx / C;
170	    int c = idx % C;
171	
172	    float m = mean[bt];
173	    float s = rstd[bt];
174	    float xi = inp[idx];
175	    float n = s * (xi - m);
176	    float o = n * weight[c] + bias[c];
177	
178	    out[idx] = o;
179	}
180	
181	__global__ void layernorm_forward_kernel3(float* __restrict__ out, float* __restrict__ mean, float* __restrict__ rstd,
182	                                    const float*  __restrict__ inp, const float*  __restrict__ weight,
183	                                    const float* __restrict__ bias, int N, int C) {
184	    namespace cg = cooperative_groups;
185	    cg::thread_block block = cg::this_thread_block();
186	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
187	    // meta_group_size is the number of warps in a block, and meta_group_rank is the warp index
188	    int idx = blockIdx.x * warp.meta_group_size() + warp.meta_group_rank();
189	    if(idx >= N) {
190	        return;
191	    }
192	
193	    // the row of input that this group of threads is responsible for
194	    const float* x = inp + idx * C;
195	
196	    // mean
197	    float sum = 0.0f;
198	    for (int i = warp.thread_rank(); i < C; i += warp.size()) {
199	        sum += x[i];
200	    }
201	    sum = cg::reduce(warp, sum, cg::plus<float>{});
202	    float m = sum / C;
203	    if(warp.thread_rank() == 0 && mean != nullptr) {
204	        __stcs(mean + idx, m);
205	    }
206	
207	    // rstd
208	    sum = 0.0f;
209	    for (int i = warp.thread_rank(); i < C; i += warp.size()) {
210	        float diff = x[i] - m;
211	        sum += diff * diff;
212	    }
213	    sum = cg::reduce(warp, sum, cg::plus<float>{});
214	    float s = rsqrtf(sum / C + 1e-5f);
215	    if(warp.thread_rank() == 0 && rstd != nullptr) {
216	        __stcs(rstd + idx, s);
217	    }
218	
219	    // final normalization and scaling by weight/bias
220	    float* o = out + idx * C;
221	    for (int c = warp.thread_rank(); c < C; c += warp.size()) {
222	        // load and store using the .cs "streaming" hint to the compiler,
223	        // indicating that this data will not be reused soon, and can be streamed through the caches
224	        // this allows the threads to get more cache-hits for the (shared) weight and bias parameters
225	        float n = s * (__ldcs(x+c) - m);
226	        __stcs(o+c, n * weight[c] + bias[c]);
227	    }
228	}
229	
230	// same as kernel 3 but uses var(x) == mean(x**2) - mean(x)**2
231	__global__ void layernorm_forward_kernel4(float* __restrict__ out, float* __restrict__ mean, float* __restrict__ rstd,
232	                                    const float*  __restrict__ inp, const float*  __restrict__ weight,
233	                                    const float* __restrict__ bias, int N, int C) {
234	    namespace cg = cooperative_groups;
235	    cg::thread_block block = cg::this_thread_block();
236	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
237	    int idx = blockIdx.x * warp.meta_group_size() + warp.meta_group_rank();
238	    if(idx >= N) {
239	        return;
240	    }
241	
242	    // the row of input that this group of threads is responsible for
243	    const float* x = inp + idx * C;
244	
245	    // thread coarsening through the row, reduce the sum in series
246	    float sum = 0.0; // stores sum(x)
247	    float sum2 = 0.0; // stores sum(x**2)
248	    for (int i = warp.thread_rank(); i < C; i += warp.size()) {
249	        float xi = x[i];
250	        sum += xi;
251	        sum2 += xi * xi;
252	    }
253	    // warp-level reduction at the end
254	    sum = cg::reduce(warp, sum, cg::plus<float>{}); // sum(x)
255	    sum2 = cg::reduce(warp, sum2, cg::plus<float>{}); // sum(x**2)
256	    sum /= C; // mean(x)
257	    sum2 /= C; // mean(x**2)
258	
259	    // mean, var, rstd
260	    float m = sum;
261	    float var = sum2 - sum * sum;
262	    float s = rsqrtf(var + 1e-5f);
263	
264	    // store the mean, no need to cache it
265	    if(warp.thread_rank() == 0 && mean != nullptr) {
266	        __stcs(mean + idx, m);
267	    }
268	    // store the rstd, no need to cache it
269	    if(warp.thread_rank() == 0 && rstd != nullptr) {
270	        __stcs(rstd + idx, s);
271	    }
272	    // final normalization and scaling by weight/bias
273	    float* o = out + idx * C;
274	    for (int c = warp.thread_rank(); c < C; c += warp.size()) {
275	        float n = s * (__ldcs(x+c) - m);
276	        __stcs(o+c, n * weight[c] + bias[c]);
277	    }
278	}
279	
280	// like 4, but in kernel 5 we have each block doing one row, not just a single warp
281	__global__ void layernorm_forward_kernel5(float* __restrict__ out, float* __restrict__ mean, float* __restrict__ rstd,
282	                                    const float*  __restrict__ inp, const float*  __restrict__ weight,
283	                                    const float* __restrict__ bias, int N, int C) {
284	    namespace cg = cooperative_groups;
285	    cg::thread_block block = cg::this_thread_block();
286	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
287	    __shared__ float shared_sum[32]; // block_size max is 1024 = 32 * 32 warps
288	    __shared__ float shared_sum2[32]; // warps will be writing into shared memeory after warp-reduce
289	    int num_warps = blockDim.x / 32;
290	    int warp_id = threadIdx.x / 32;
291	    int lane_id = threadIdx.x % 32;
292	    int idx = blockIdx.x; // simply one block per row
293	    // the row of input that this group of threads is responsible for
294	    const float* x = inp + idx * C;
295	    // thread coarsening through the row, reduce the sum in series
296	    float thread_sum = 0.0; // stores sum(x)
297	    float thread_sum2 = 0.0; // stores sum(x**2)
298	    // for (int i = C + threadIdx.x - blockDim.x; i >= 0; i -= blockDim.x) {
299	    for (int i = threadIdx.x; i < C; i += blockDim.x) {
300	        float xi = x[i];
301	        thread_sum += xi;
302	        thread_sum2 += xi * xi;
303	    }
304	    // warp-level reduction
305	    float warp_sum = cg::reduce(warp, thread_sum, cg::plus<float>{}); // sum(x)
306	    float warp_sum2 = cg::reduce(warp, thread_sum2, cg::plus<float>{}); // sum(x**2)
307	    // store the warp-level reduction in shared memory (we could have lane_id == 0 guard but not needed)
308	    shared_sum[warp_id] = warp_sum;
309	    shared_sum2[warp_id] = warp_sum2;
310	    __syncthreads();
311	    // load results from shared memory to threads, pad with zeros for threads that are out of bounds
312	    warp_sum = (lane_id < num_warps) ? shared_sum[lane_id] : 0.0f;
313	    warp_sum2 = (lane_id < num_warps) ? shared_sum2[lane_id] : 0.0f;
314	    // now reduce the warp-level reductions
315	    float block_sum = cg::reduce(warp, warp_sum, cg::plus<float>{}); // sum(x)
316	    float block_sum2 = cg::reduce(warp, warp_sum2, cg::plus<float>{}); // sum(x**2)
317	    // mean, var, rstd
318	    block_sum /= C; // mean(x)
319	    block_sum2 /= C; // mean(x**2)
320	    float m = block_sum;
321	    float var = block_sum2 - m * m;
322	    float s = rsqrtf(var + 1e-5f);
323	    // store the mean, no need to cache it
324	    if(threadIdx.x == 0 && mean != nullptr) {
325	        __stcs(mean + idx, m);
326	    }
327	    // store the rstd, no need to cache it
328	    if(threadIdx.x == 0 && rstd != nullptr) {
329	        __stcs(rstd + idx, s);
330	    }
331	    // final normalization and scaling by weight/bias
332	    float* o = out + idx * C;
333	    for (int i = threadIdx.x; i < C; i += blockDim.x) {
334	        float n = s * (__ldcs(x+i) - m);
335	        __stcs(o+i, n * weight[i] + bias[i]);
336	    }
337	}
338	
339	// Inspired by `fused_residual_forward_kernel5` in fused_residual_forward.cu
340	__global__ void layernorm_forward_kernel6(float* __restrict__ out, float* __restrict__ mean, float* __restrict__ rstd,
341	                                    const float*  __restrict__ inp, const float*  __restrict__ weight,
342	                                    const float* __restrict__ bias, int N, int C) {
343	    assert(blockDim.x == WARP_SIZE);
344	
345	    // load weights and biases into shared memory
346	    // do this before we allow any threads to exit!
347	    extern __shared__ char params[];
348	    // load128/store128 sometimes generated multiple instructions when the types here were floatX*, so
349	    // let's keep everything as x128
350	    x128* s_weight = reinterpret_cast<x128*>(params);
351	    x128* s_bias = reinterpret_cast<x128*>(params) + (C / x128::size);
352	    x128* s_in = reinterpret_cast<x128*>(params) + ((2 + threadIdx.y) * C / x128::size);
353	
354	    int sidx = (threadIdx.x + WARP_SIZE * threadIdx.y) * x128::size;
355	    for(int i = sidx; i < C; i += blockDim.y * WARP_SIZE * x128::size) {
356	        s_weight[i/x128::size] = load128(weight + i);
357	        s_bias[i/x128::size] = load128(bias + i);
358	    }
359	    __syncthreads();
360	
361	    int idx = blockIdx.x * blockDim.y + threadIdx.y;
362	    if(idx >= N) { return; } // guard
363	
364	    // adjust pointers to current token
365	    inp += idx * C;
366	    out += idx * C;
367	
368	    const float eps = 1e-5f;
369	    float sum = 0.0f;
370	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
371	        const x128 in_data = load128cs(inp + c);
372	        for(int k = 0; k < x128::size; ++k) {
373	            sum += (float)in_data[k];
374	        }
375	        s_in[c / x128::size] = in_data;
376	    }
377	
378	    sum = warpReduceSum(sum);
379	    float m = sum / C;
380	    float v = 0.f;
381	
382	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
383	        const x128 in_data = s_in[c / x128::size];
384	        for(int k = 0; k < x128::size; ++k) {
385	            v += ((float)in_data[k] - m) * ((float)in_data[k] - m);
386	        }
387	    }
388	
389	    v = warpReduceSum(v) / C;
390	    float s = rsqrtf(v + eps);
391	
392	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
393	        const x128 in_data = s_in[c / x128::size];
394	        const x128 w = s_weight[c / x128::size];
395	        const x128 b = s_bias[c / x128::size];
396	        x128 out_data;
397	        for(int k = 0; k < x128::size; ++k) {
398	            float n = s * ((float)in_data[k] - m); // normalized output
399	            float o = n * (float)w[k] + (float)b[k]; // scale and shift it
400	            out_data[k] = o;
401	        }
402	
403	        store128cs(out + c, out_data);
404	    }
405	    // cache the mean and rstd for the backward pass later
406	    if(threadIdx.x == 0 && mean != nullptr) {
407	        __stcs(mean + idx, m);
408	    }
409	    // store the rstd, no need to cache it
410	    if(threadIdx.x == 0 && rstd != nullptr) {
411	        __stcs(rstd + idx, s);
412	    }
413	}
414	
415	// ----------------------------------------------------------------------------
416	// kernel launcher
417	
418	void layernorm_forward1(float* out, float* mean, float* rstd,
419	                           const float* inp, const float* weight, const float* bias,
420	                           int B, int T, int C,
421	                           const int block_size) {
422	    const int N = B * T;
423	    const int grid_size = ceil_div(N, block_size);
424	    layernorm_forward_kernel1<<<grid_size, block_size>>>(out, mean, rstd, inp, weight, bias, N, C);
425	    cudaCheck(cudaGetLastError());
426	}
427	
428	void layernorm_forward2(float* out, float* mean, float* rstd,
429	                       const float* inp, const float* weight, const float* bias,
430	                       int B, int T, int C,
431	                       const int block_size) {
432	    int N = B * T;
433	    // in mean and rstd, threads cooperate within blocks via reductions
434	    mean_kernel<<<N, block_size, block_size * sizeof(float)>>>(mean, inp, N, C, block_size);
435	    cudaCheck(cudaGetLastError());
436	    rstd_kernel<<<N, block_size, block_size * sizeof(float)>>>(rstd, inp, mean, N, C, block_size);
437	    cudaCheck(cudaGetLastError());
438	    // in the normalization, everything just gets flattened out
439	    const int block_size2 = 256;
440	    const int grid_size = ceil_div(B * T * C, block_size2);
441	    normalization_kernel<<<grid_size, block_size2>>>(out, inp, mean, rstd, weight, bias, B, T, C);
442	    cudaCheck(cudaGetLastError());
443	}
444	
445	void layernorm_forward3(float* out, float* mean, float* rstd,
446	                       const float* inp, const float* weight, const float* bias,
447	                       int B, int T, int C,
448	                       const int block_size) {
449	    assert(block_size % 32 == 0);
450	    const int N = B * T;
451	    const int grid_size = ceil_div(N * 32, block_size);
452	    layernorm_forward_kernel3<<<grid_size, block_size>>>(out, mean, rstd, inp, weight, bias, N, C);
453	    cudaCheck(cudaGetLastError());
454	}
