456	void layernorm_forward4(float* out, float* mean, float* rstd,
457	                       const float* inp, const float* weight, const float* bias,
458	                       int B, int T, int C,
459	                       const int block_size) {
460	    assert(block_size % 32 == 0);
461	    const int N = B * T;
462	    const int grid_size = ceil_div(N * 32, block_size);
463	    layernorm_forward_kernel4<<<grid_size, block_size>>>(out, mean, rstd, inp, weight, bias, N, C);
464	    cudaCheck(cudaGetLastError());
