467	void layernorm_forward5(float* out, float* mean, float* rstd,
468	                       const float* inp, const float* weight, const float* bias,
469	                       int B, int T, int C,
470	                       const int block_size) {
471	    assert(block_size % 32 == 0);
472	    assert(block_size <= 1024);
473	    const int N = B * T;
474	    const int grid_size = N;
475	    layernorm_forward_kernel5<<<grid_size, block_size>>>(out, mean, rstd, inp, weight, bias, N, C);
476	    cudaCheck(cudaGetLastError());
477	}
478	
479	void layernorm_forward6(float* out, float* mean, float* rstd,
480	                       const float* inp, const float* weight, const float* bias,
481	                       int B, int T, int C,
482	                       int block_size) {
483	    assert(block_size % 32 == 0);
484	    const int N = B * T;
485	    int block_y = block_size / WARP_SIZE;
486	    const int grid_size = ceil_div(N, block_y);
487	    size_t smem = (2 + block_y) * C * sizeof(float);
488	
489	    // in order to use more than 48 KiB of smem, need to call cudaFuncSetAttribute
490	    // this may fail, in which case we fall back to the smem free implementation.
491	    cudaCheck(cudaGetLastError());
492	    auto status = cudaFuncSetAttribute(layernorm_forward_kernel6, cudaFuncAttributeMaxDynamicSharedMemorySize, smem);
493	    cudaGetLastError();
494	    if (status == cudaSuccess) {
495	        layernorm_forward_kernel6<<<grid_size, dim3(32, block_y), smem>>>(out, mean, rstd, inp, weight, bias, N, C);
496	    } else {
497	        const int grid_size = N;
498	        // fall back to the version without shared memory
499	        layernorm_forward_kernel5<<<grid_size, block_size>>>(out, mean, rstd, inp, weight, bias, N, C);
500	    }
501	    cudaCheck(cudaGetLastError());
502	}
503	
504	// kernel version dispatch
505	void layernorm_forward(int kernel_num,
506	                    float* out, float* mean, float* rstd,
507	                    const float* inp, const float* weight, const float* bias,
508	                    int B, int T, int C,
509	                    const int block_size) {
510	    switch (kernel_num) {
511	        case 1:
512	            layernorm_forward1(out, mean, rstd, inp, weight, bias, B, T, C, block_size);
513	            break;
514	        case 2:
515	            layernorm_forward2(out, mean, rstd, inp, weight, bias, B, T, C, block_size);
516	            break;
517	        case 3:
518	            layernorm_forward3(out, mean, rstd, inp, weight, bias, B, T, C, block_size);
519	            break;
520	        case 4:
521	            layernorm_forward4(out, mean, rstd, inp, weight, bias, B, T, C, block_size);
522	            break;
523	        case 5:
524	            layernorm_forward5(out, mean, rstd, inp, weight, bias, B, T, C, block_size);
525	            break;
526	        case 6:
527	            layernorm_forward6(out, mean, rstd, inp, weight, bias, B, T, C, block_size);
528	            break;
529	        default:
530	            printf("Invalid kernel number\n");
531	            exit(1);
532	    }
533	}
534	
535	// ----------------------------------------------------------------------------
536	
537	int main(int argc, char **argv) {
538	    srand(0);
539	
540	    int B = 8;
541	    int T = 1024;
542	    int C = 768;
543	
544	    int deviceIdx = 0;
545	    cudaCheck(cudaSetDevice(deviceIdx));
546	
547	    // create host memory of random numbers
548	    float* out = (float*)malloc(B * T * C * sizeof(float));
549	    float* mean = (float*)malloc(B * T * sizeof(float));
550	    float* rstd = (float*)malloc(B * T * sizeof(float));
551	    float* inp = make_random_float(B * T * C);
552	    float* weight = make_random_float(C);
553	    float* bias = make_random_float(C);
554	
555	    // move to GPU
556	    float* d_out;
557	    float* d_mean;
558	    float* d_rstd;
559	    float* d_inp;
560	    float* d_weight;
561	    float* d_bias;
562	    cudaCheck(cudaMalloc(&d_out, B * T * C * sizeof(float)));
563	    cudaCheck(cudaMalloc(&d_mean, B * T * sizeof(float)));
564	    cudaCheck(cudaMalloc(&d_rstd, B * T * sizeof(float)));
565	    cudaCheck(cudaMalloc(&d_inp, B * T * C * sizeof(float)));
566	    cudaCheck(cudaMalloc(&d_weight, C * sizeof(float)));
567	    cudaCheck(cudaMalloc(&d_bias, C * sizeof(float)));
568	    cudaCheck(cudaMemcpy(d_inp, inp, B * T * C * sizeof(float), cudaMemcpyHostToDevice));
569	    cudaCheck(cudaMemcpy(d_weight, weight, C * sizeof(float), cudaMemcpyHostToDevice));
570	    cudaCheck(cudaMemcpy(d_bias, bias, C * sizeof(float), cudaMemcpyHostToDevice));
571	
572	    // read kernel_num from command line
573	    int kernel_num = 2;
574	    if (argc > 1) {
575	        kernel_num = atoi(argv[1]);
576	    }
577	    printf("Using kernel %d\n", kernel_num);
578	
579	    int block_sizes[] = {32, 64, 128, 256, 512, 1024};
580	
581	    layernorm_forward_cpu(out, mean, rstd, inp, weight, bias, B, T, C);
582	
583	    // check the correctness of the kernel at all block sizes
584	    for (int j = 0; j < sizeof(block_sizes) / sizeof(int); j++) {
585	        int block_size = block_sizes[j];
586	        printf("Checking block size %d.\n", block_size);
587	
588	        layernorm_forward(kernel_num, d_out, d_mean, d_rstd, d_inp, d_weight, d_bias, B, T, C, block_size);
589	
590	        validate_result(d_out, out, "out", B * T * C, 1e-5f);
591	        validate_result(d_mean, mean, "mean", B * T, 1e-5f);
592	        validate_result(d_rstd, rstd, "rstd", B * T, 1e-5f);
593	    }
594	
595	    printf("All results match. Starting benchmarks.\n\n");
596	
597	    // time the kernel at different block sizes
598	    for (int j = 0; j < sizeof(block_sizes) / sizeof(int); j++) {
599	        int block_size = block_sizes[j];
600	
601	        int repeat_times = 2000;
602	        float elapsed_time = benchmark_kernel(repeat_times, layernorm_forward,
603	                                              kernel_num, d_out, d_mean, d_rstd, d_inp, d_weight, d_bias,
604	                                              B, T, C, block_size);
605	
606	        // napkin math: estimate the memory bandwidth achieved
607	        // e.g. A100 40GB PCIe is advertised at 1,555GB/s
608	        long memory_ops = (2 * B * T * C) * 4; // *4 for float
609	        float memory_bandwidth = memory_ops / elapsed_time / 1e6;
610	
611	        printf("block_size %4d | time %.4f ms | bandwidth %.2f GB/s\n", block_size, elapsed_time, memory_bandwidth);
612	    }
613	
614	    // free memory
615	    free(out);
616	    free(mean);
617	    free(rstd);
618	    free(inp);
619	    free(weight);
620	    free(bias);
621	    cudaCheck(cudaFree(d_out));
622	    cudaCheck(cudaFree(d_mean));
623	    cudaCheck(cudaFree(d_rstd));
624	    cudaCheck(cudaFree(d_inp));
